import React from 'react';
import { NavLink } from 'react-router-dom';

const navItems = [
  { to: '/', label: 'Dashboard', icon: '📊' },
  { to: '/patients', label: 'Patients', icon: '👥' },
  { to: '/patients/new', label: 'Add Patient', icon: '➕' },
];

export default function Sidebar() {
  return (
    <aside style={{
      width: 220, minHeight: '100vh', background: '#fff',
      borderRight: '1px solid #e2e8f0', display: 'flex', flexDirection: 'column',
      position: 'fixed', top: 0, left: 0, zIndex: 10
    }}>
      <div style={{ padding: '20px 20px 16px', borderBottom: '1px solid #e2e8f0' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
          <div style={{ width: 36, height: 36, borderRadius: 8, background: '#2b7de9', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 18 }}>🏥</div>
          <div>
            <div style={{ fontWeight: 700, fontSize: 13, color: '#1a202c' }}>Rural Health</div>
            <div style={{ fontSize: 11, color: '#64748b' }}>Record System</div>
          </div>
        </div>
      </div>
      <nav style={{ flex: 1, padding: '12px 10px' }}>
        {navItems.map(item => (
          <NavLink key={item.to} to={item.to} end={item.to === '/'}
            style={({ isActive }) => ({
              display: 'flex', alignItems: 'center', gap: 10,
              padding: '9px 12px', borderRadius: 6, marginBottom: 2,
              textDecoration: 'none', fontSize: 13, fontWeight: 500,
              color: isActive ? '#2b7de9' : '#374151',
              background: isActive ? '#e8f0fd' : 'transparent',
              transition: 'all 0.12s'
            })}>
            <span style={{ fontSize: 15 }}>{item.icon}</span>
            {item.label}
          </NavLink>
        ))}
      </nav>
      <div style={{ padding: '12px 16px', borderTop: '1px solid #e2e8f0', fontSize: 11, color: '#94a3b8' }}>
        Anantapur PHC — 2026
      </div>
    </aside>
  );
}
